requiere_roles(['ADMIN','TI','RRHH','DIRECTOR','GERENCIA','CEO'], '../');
$pdo=db();$actor=usuario_actual();$msg=null;
if($_SERVER['REQUEST_METHOD']==='POST'&&($_POST['accion']??'')==='crear_ciclo'){
    try{
        $datos=$_POST;$documento=limpio($_POST['empleado_documento']??null);
        if($documento){$s=$pdo->prepare('SELECT * FROM empleados WHERE documento=?');$s->execute([$documento]);if($e=$s->fetch(PDO::FETCH_ASSOC)){$datos['empleado_nombre']=$e['nombres'];$datos['correo_corporativo']=$e['email'];$datos['cargo']=$e['cargo'];$datos['area_origen']=$e['area'];$datos['area_destino']=$datos['area_destino']?:$e['area'];}}
        $ciclo=ciclo_identidad_crear($pdo,$datos,$actor);header('Location: ciclo_identidad_detalle.php?id='.(int)$ciclo['id'].'&creado=1');exit;
    }catch(Throwable $e){$msg=['error',$e->getMessage()];}
}
$diag=identidad_diagnostico($pdo);$filtro=strtoupper((string)($_GET['brecha']??'SIN_NAVISSI'));if(!in_array($filtro,['SIN_NAVISSI','SIN_MICROSOFT','RETIRO_ACTIVO','MICROSOFT_SIN_EMPLEADO'],true))$filtro='SIN_NAVISSI';$brechas=identidad_brechas($pdo,$filtro);$ciclos=$pdo->query('SELECT * FROM ciclos_identidad ORDER BY CASE estado WHEN \'EN_EJECUCION\' THEN 0 WHEN \'APROBADO\' THEN 1 WHEN \'PENDIENTE\' THEN 2 ELSE 3 END,id DESC LIMIT 30')->fetchAll(PDO::FETCH_ASSOC);$empleados=$pdo->query("SELECT documento,nombres,email,area,cargo,estado FROM empleados ORDER BY nombres")->fetchAll(PDO::FETCH_ASSOC);$departamentos=$pdo->query("SELECT nombre FROM departamentos WHERE estado='ACTIVO' ORDER BY nombre")->fetchAll(PDO::FETCH_COLUMN);$solicitudes=$pdo->query("SELECT id,codigo,solicitante_nombre,descripcion FROM solicitudes_aprobacion WHERE estado='APROBADA' AND tipo='USR-ALTA-BAJA' AND id NOT IN(SELECT solicitud_id FROM ciclos_identidad WHERE solicitud_id IS NOT NULL) ORDER BY id DESC")->fetchAll(PDO::FETCH_ASSOC);$solicitudPre=(int)($_GET['solicitud_id']??0);$graphOk=ms365_configurado();
layout_inicio('Gobierno de Identidades','Gobierno de Identidades','../');?>
