<div class="panel-grid-2"><section class="panel"><h3>Iniciar ciclo de identidad</h3><form method="post"><input type="hidden" name="accion" value="crear_ciclo"><div class="grid-form"><div><label>Tipo</label><select name="tipo"><option>ALTA</option><option>TRASLADO</option><option>RETIRO</option></select></div><div><label>Empleado registrado</label><select name="empleado_documento"><option value="">Captura manual</option><?php foreach($empleados as $e):?><option value="<?=e($e['documento'])?>"><?=e($e['nombres'])?> · <?=e($e['estado'])?></option><?php endforeach;?></select></div><div><label>Nombre (si es alta nueva)</label><input name="empleado_nombre"></div><div><label>Correo corporativo</label><input type="email" name="correo_corporativo"></div><div><label>Cargo</label><input name="cargo"></div><div><label>Área de destino</label><select name="area_destino"><option value="">Selecciona</option><?php foreach($departamentos as $d):?><option><?=e($d)?></option><?php endforeach;?></select></div><div><label>Fecha efectiva</label><input type="date" name="fecha_efectiva"></div><div><label>Solicitud aprobada</label><select name="solicitud_id"><option value="">Pendiente de aprobación</option><?php foreach($solicitudes as $s):?><option value="<?=(int)$s['id']?>" <?=$solicitudPre===(int)$s['id']?'selected':''?>><?=e($s['codigo'])?> · <?=e($s['solicitante_nombre'])?></option><?php endforeach;?></select></div></div><label>Observaciones</label><textarea name="observaciones" rows="2"></textarea><button style="margin-top:12px">Crear plan de tareas</button></form></section><section class="panel"><h3>Brecha priorizada</h3><div class="toolbar"><a class="btn btn-secondary" href="?brecha=SIN_NAVISSI">NAVISSI</a><a class="btn btn-secondary" href="?brecha=SIN_MICROSOFT">Microsoft</a><a class="btn btn-secondary" href="?brecha=RETIRO_ACTIVO">Retiros</a></div><table><thead><tr><th>Persona / cuenta</th><th>Área</th><th>Acción</th></tr></thead><tbody><?php foreach($brechas as $b):?><tr><td><strong><?=e($b['nombres'])?></strong><br><span class="small"><?=e($b['email'])?></span></td><td><?=e($b['area'])?></td><td><?=e($b['accion'])?></td></tr><?php endforeach;?><?php if(!$brechas):?><tr><td colspan="3" class="small">No hay brechas de este tipo.</td></tr><?php endif;?></tbody></table></section></div>
<section class="panel"><h3>Ciclos recientes</h3><table><thead><tr><th>Código</th><th>Tipo</th><th>Empleado</th><th>Fecha efectiva</th><th>Progreso</th><th>Estado</th></tr></thead><tbody><?php foreach($ciclos as $c):?><tr onclick="location.href='ciclo_identidad_detalle.php?id=<?=(int)$c['id']?>'" style="cursor:pointer"><td><strong><?=e($c['codigo'])?></strong></td><td><?=e($c['tipo'])?></td><td><?=e($c['empleado_nombre'])?><br><span class="small"><?=e($c['correo_corporativo'])?></span></td><td><?=e($c['fecha_efectiva'])?></td><td><div class="cycle-progress"><span style="width:<?=(int)$c['progreso']?>%"></span></div><small><?=(int)$c['progreso']?>%</small></td><td><span class="badge <?=$c['estado']==='COMPLETADO'?'badge-activo':($c['estado']==='PENDIENTE'?'badge-warn':'badge-otro')?>"><?=e($c['estado'])?></span></td></tr><?php endforeach;?><?php if(!$ciclos):?><tr><td colspan="6" class="small">Todavía no hay ciclos creados.</td></tr><?php endif;?></tbody></table></section>
<?php layout_fin();?>
